import{_ as e}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as t,o as i,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Auto Tagging","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Other/auto-tagging.md","filePath":"hi/Other/auto-tagging.md","lastUpdated":1781962217000}'),o={name:"hi/Other/auto-tagging.md"};function n(d,a,c,g,p,r){return i(),s("div",null,[...a[0]||(a[0]=[l('<h1 id="auto-tagging" tabindex="-1">Auto Tagging <a class="header-anchor" href="#auto-tagging" aria-label="Permalink to &quot;Auto Tagging&quot;">​</a></h1><p>Auto tagging यहाँ configure किया जाता है:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>यह images के लिए tags automatically generate करता है। ये tags search, random image filtering, public gallery filtering और age-rating access control में काम आते हैं।</p><h2 id="auto-tagging-क्या-कर-सकता-है" tabindex="-1">Auto Tagging क्या कर सकता है <a class="header-anchor" href="#auto-tagging-क्या-कर-सकता-है" aria-label="Permalink to &quot;Auto Tagging क्या कर सकता है&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td>Content tags generate करना</td><td>People, scenes, objects, art style और मिलते-जुलते visual content के tags जोड़ता है।</td></tr><tr><td>Character tags generate करना</td><td>Anime images और illustrations के लिए उपयोगी।</td></tr><tr><td>Orientation tags जोड़ना</td><td><code>landscape</code>, <code>portrait</code> या <code>square</code> जोड़ता है।</td></tr><tr><td>Image rating जोड़ना</td><td>General, sensitive, questionable या explicit content के लिए <code>G/S/Q/E</code> rating results save करता है।</td></tr><tr><td>Upload पर auto-tag</td><td>Newly uploaded images automatically tagging flow में चली जाती हैं।</td></tr><tr><td>Batch tagging</td><td>सभी folders या selected folders की पुरानी images में tags जोड़ता है।</td></tr></tbody></table><h2 id="पहले-क्या-चाहिए" tabindex="-1">पहले क्या चाहिए <a class="header-anchor" href="#पहले-क्या-चाहिए" aria-label="Permalink to &quot;पहले क्या चाहिए&quot;">​</a></h2><p>कम से कम एक accessible Hugging Face Space URL तैयार रखें।</p><p>Recommended तरीका है SmilingWolf के <code>wd-tagger</code> Space को अपने Hugging Face account में duplicate करना:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Temporary testing के लिए public Space इस्तेमाल कर सकते हैं, लेकिन public Spaces कई users के बीच share होते हैं। Queue लग सकती है, speed slow हो सकती है या Space unavailable भी हो सकता है। अपने account में duplicated Space long-term auto tagging के लिए ज़्यादा stable रहता है।</p><h2 id="smilingwolf-का-space-duplicate-करना" tabindex="-1">SmilingWolf का Space Duplicate करना <a class="header-anchor" href="#smilingwolf-का-space-duplicate-करना" aria-label="Permalink to &quot;SmilingWolf का Space Duplicate करना&quot;">​</a></h2><ol><li>Hugging Face में sign in करें।</li><li><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code> खोलें।</li></ol><p><img src="'+e+`" alt="SmilingWolf public Space" loading="lazy"></p><ol start="3"><li>Upper-right corner में three-dot menu पर click करें।</li><li><code>Duplicate this Space</code> चुनें।</li><li>Default Space name रखें या अपना नाम चुनें, जैसे <code>wd-tagger</code>।</li><li>Visibility को <code>Public</code> रखें। Public Spaces को ImgBed से call करना आसान होता है।</li><li>शुरुआत में default free hardware रखें। Queueing ज़्यादा दिखे तभी बाद में upgrade करें।</li><li>Space create करें और build finish होने तक इंतज़ार करें।</li></ol><p>Build finish होने के बाद अपना Space page खोलें। URL आम तौर पर ऐसा दिखेगा:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Browser URL copy करें और ImgBed के <code>Space URLs</code> में paste करें।</p><h2 id="multiple-space-urls-भरना" tabindex="-1">Multiple Space URLs भरना <a class="header-anchor" href="#multiple-space-urls-भरना" aria-label="Permalink to &quot;Multiple Space URLs भरना&quot;">​</a></h2><p>हर line में एक Space URL डालें।</p><p>Examples:</p><table tabindex="0"><thead><tr><th>Value</th><th>Description</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>SmilingWolf public Space। Temporary testing के लिए ठीक।</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>Copied Space page URL।</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>आपका duplicated Space page URL।</td></tr></tbody></table><p>आप multiple URLs डाल सकते हैं। ImgBed कई Spaces को साथ में इस्तेमाल करता है, जिससे speed बेहतर हो सकती है।</p><p>अगर एक Space temporarily unavailable है, तो दूसरे Spaces processing जारी रख सकते हैं।</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>तैयार किए गए Space URLs डालें। कम से कम एक URL ज़रूर दें।</td></tr><tr><td>Target folder</td><td>सभी folders के लिए empty छोड़ें। Specific directory process करनी हो तभी folder select करें।</td></tr><tr><td>Recognition model</td><td>Default में <code>wd-swinv2-tagger-v3</code> रखें।</td></tr><tr><td>General tag threshold</td><td>Default ज़्यादातर images के लिए ठीक है। Lower value से ज़्यादा tags मिलते हैं; higher value से कम tags।</td></tr><tr><td>Character tag threshold</td><td>Default conservative है और गलत character tags से बचने में मदद करता है।</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>शुरुआत में off रखें। जब model से tag count automatically तय करवाना हो तब on करें।</td></tr><tr><td>Auto-tag on upload</td><td>Newly uploaded images को automatically tags देने हों तो on करें।</td></tr><tr><td>Start tagging</td><td>पुरानी images को manually batch-tag करता है।</td></tr></tbody></table><h2 id="recommended-starting-values" tabindex="-1">Recommended Starting Values <a class="header-anchor" href="#recommended-starting-values" aria-label="Permalink to &quot;Recommended Starting Values&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Recommended Value</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>शुरुआत में Off</td></tr><tr><td>Auto-tag on upload</td><td>ज़रूरत हो तो Enable</td></tr></tbody></table><p>अगर tags बहुत ज़्यादा आ रहे हैं, तो general threshold थोड़ा बढ़ाएँ।</p><p>अगर tags बहुत कम आ रहे हैं, तो general threshold थोड़ा घटाएँ।</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li><code>Space URLs</code> भरें।</li><li>Target folder select करें।</li><li>Start tagging पर click करें।</li><li>Progress finish होने तक इंतज़ार करें।</li></ol><p>अगर target folder empty है, तो ImgBed सभी folders process करता है।</p><p>Batch tagging पुरानी images के लिए बेहतर है। New images के लिए auto-tag on upload enable करें, ताकि हर बार manually run न करना पड़े।</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Auto-tag on upload enabled होने के बाद newly uploaded images automatically configured <code>Space URLs</code> को call करती हैं।</p><p>यह long-term use के लिए suitable है।</p><p>अगर आपका Space queue में है, तो upload पहले finish हो सकता है और tagging बाद में continue होती है।</p><h2 id="कौन-सी-images-process-होती-हैं" tabindex="-1">कौन सी Images Process होती हैं <a class="header-anchor" href="#कौन-सी-images-process-होती-हैं" aria-label="Permalink to &quot;कौन सी Images Process होती हैं&quot;">​</a></h2><p>Auto tagging मुख्य रूप से image files process करता है।</p><p>जिन images में complete tags, orientation, rating, width और height पहले से मौजूद हैं, उन्हें unnecessary Space calls से बचाने के लिए skip किया जाता है।</p><p>ImgBed जहाँ संभव हो केवल missing information भरता है। उदाहरण के लिए, अगर सिर्फ orientation missing है, तो full content tag flow call किए बिना orientation जोड़ने की कोशिश करता है।</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="अपना-space-duplicate-क्यों-करें" tabindex="-1">अपना Space Duplicate क्यों करें? <a class="header-anchor" href="#अपना-space-duplicate-क्यों-करें" aria-label="Permalink to &quot;अपना Space Duplicate क्यों करें?&quot;">​</a></h3><p>Public Spaces कई users के बीच shared होते हैं। आपका duplicated Space मुख्य रूप से आपकी ImgBed site इस्तेमाल करती है, इसलिए वह आम तौर पर तेज़ और reliable रहता है।</p><h3 id="space-बार-बार-starting-up-दिखा-रहा-है" tabindex="-1">Space बार-बार Starting Up दिखा रहा है <a class="header-anchor" href="#space-बार-बार-starting-up-दिखा-रहा-है" aria-label="Permalink to &quot;Space बार-बार Starting Up दिखा रहा है&quot;">​</a></h3><p>पहली बार creation के बाद, या लंबे idle period के बाद, Space को start होने में समय लग सकता है।</p><p>पहले अपना Space page खोलें। जब वह normal image recognize कर सके, तब ImgBed पर लौटकर tagging start करें।</p><h3 id="space-url-कैसे-copy-करें" tabindex="-1">Space URL कैसे Copy करें? <a class="header-anchor" href="#space-url-कैसे-copy-करें" aria-label="Permalink to &quot;Space URL कैसे Copy करें?&quot;">​</a></h3><p>अपना Hugging Face Space page खोलें और browser address copy करें।</p><p>Examples:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="क्या-multiple-spaces-जोड़-सकते-हैं" tabindex="-1">क्या Multiple Spaces जोड़ सकते हैं? <a class="header-anchor" href="#क्या-multiple-spaces-जोड़-सकते-हैं" aria-label="Permalink to &quot;क्या Multiple Spaces जोड़ सकते हैं?&quot;">​</a></h3><p>हाँ। हर line में एक Space URL डालें।</p><p>Multiple Spaces images को साथ में process करते हैं और तब useful होते हैं जब images बहुत ज़्यादा हों।</p><h3 id="tags-english-में-क्यों-हैं" tabindex="-1">Tags English में क्यों हैं? <a class="header-anchor" href="#tags-english-में-क्यों-हैं" aria-label="Permalink to &quot;Tags English में क्यों हैं?&quot;">​</a></h3><p>SmilingWolf models English tags output करते हैं। यह expected है।</p><p>Tags मुख्य रूप से search, filtering, random image API और public gallery filters के लिए इस्तेमाल होते हैं।</p><h3 id="rating-tags-किस-काम-आते-हैं" tabindex="-1">Rating Tags किस काम आते हैं? <a class="header-anchor" href="#rating-tags-किस-काम-आते-हैं" aria-label="Permalink to &quot;Rating Tags किस काम आते हैं?&quot;">​</a></h3><p>Rating results Security Settings के access mode के साथ काम करते हैं।</p><p>उदाहरण के लिए, जब visitor access age rating से limited हो, तो public browsing और random image features उन्हीं rules के हिसाब से images filter करते हैं।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face में sign in करें</span></span>
<span class="line"><span>-&gt; SmilingWolf/wd-tagger खोलें</span></span>
<span class="line"><span>-&gt; Duplicate this Space करें</span></span>
<span class="line"><span>-&gt; Space build होने तक इंतज़ार करें</span></span>
<span class="line"><span>-&gt; अपना Space URL copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में Space URLs भरें</span></span>
<span class="line"><span>-&gt; Model और thresholds चुनें</span></span>
<span class="line"><span>-&gt; Start tagging करें या auto-tag on upload enable करें</span></span></code></pre></div>`,63)])])}const b=t(o,[["render",n]]);export{m as __pageData,b as default};
